package main

import (
	"html/template"
	"log"
	"net/http"
)

type Comment struct {
	Author string
	Body   template.HTML
}

var comments = []Comment{
	{Author: "Alice", Body: template.HTML("Hello, <b>world</b>!")},
	{Author: "Bob", Body: template.HTML("This is <i>formatted</i> text.")},
	{Author: "Carol", Body: template.HTML("Visit <a href=\"https://example.com\">example.com</a>")},
}

var pageTmpl = template.Must(template.New("comments").Parse(`
<!DOCTYPE html>
<html lang="en">
<head>
	<meta charset="UTF-8">
	<meta name="viewport" content="width=device-width, initial-scale=1.0">
	<title>Comments</title>
	<style>
		body { font-family: Arial, sans-serif; margin: 2rem; }
		.comment { border-bottom: 1px solid #ddd; padding: 1rem 0; }
		.author { font-weight: bold; margin-bottom: 0.5rem; }
	</style>
</head>
<body>
	<h1>User Comments</h1>
	{{range .}}
	<div class="comment">
		<div class="author">{{.Author}}</div>
		<div class="body">{{.Body}}</div>
	</div>
	{{else}}
	<p>No comments yet.</p>
	{{end}}
</body>
</html>
`))

func commentsHandler(w http.ResponseWriter, r *http.Request) {
	w.Header().Set("Content-Type", "text/html; charset=utf-8")
	if err := pageTmpl.Execute(w, comments); err != nil {
		http.Error(w, "failed to render comments", http.StatusInternalServerError)
		return
	}
}

func main() {
	http.HandleFunc("/comments", commentsHandler)
	log.Println("listening on :8080")
	log.Fatal(http.ListenAndServe(":8080", nil))
}